function getUD(id) {
  return userData[id] || { conf: (RAW_PROBLEMS.find(p=>p.id===id) || {}).conf || 0, comment: '', reviewed: 0, lastReviewed: null };
}

function getConf(p) {
  const ud = userData[p.id];
  if (ud) {
    if (ud.manualConf) return ud.conf;
    if (ud.conf > 0) return ud.conf;
  }
  if (p.conf > 0) return p.conf;
  if (p.date) {
    const parts = p.date.split(' ');
    if (parts.length === 3) {
      const solved = new Date(parts[1] + ' ' + parts[0] + ', ' + parts[2]);
      if (!isNaN(solved)) {
        const months = (Date.now() - solved.getTime()) / (1000 * 60 * 60 * 24 * 30.44);
        if (months <= 1) return 5;
        if (months <= 2) return 4;
        if (months <= 4) return 3;
        if (months <= 6) return 2;
        return 1;
      }
    }
  }
  return 0;
}

function getConfForXP(p) {
  const ud = userData[p.id];
  if (ud && ud.manualConf) return ud.conf;
  if (ud && ud.conf > 0) return ud.conf;
  if (p.conf > 0) return p.conf;
  if (p.date) {
    const parts = p.date.split(' ');
    if (parts.length === 3) {
      const d = new Date(parts[1] + ' ' + parts[0] + ', ' + parts[2]);
      if (!isNaN(d)) return 1;
    }
  }
  return 0;
}

function getDueInfo(p) {
  const c = getConf(p);
  const ud = userData[p.id];
  const now = Date.now();
  const DAY = 86400000;
  let lastMs = null;
  if (ud && ud.lastReviewed) {
    lastMs = new Date(ud.lastReviewed).getTime();
  } else if (p.date) {
    const parts = p.date.split(' ');
    if (parts.length === 3) {
      const d = new Date(parts[1] + ' ' + parts[0] + ', ' + parts[2]);
      if (!isNaN(d)) lastMs = d.getTime();
    }
  }
  if (lastMs === null) return { days: -999, label: 'New', cls: 'due-new' };
  // Unrated problems (c=0) use a 30-day default so they don't all show as overdue
  const interval = c > 0 ? SR_INTERVALS[Math.min(c, 5)] : 30;
  const elapsed = Math.floor((now - lastMs) / DAY);
  const dueIn = interval - elapsed;
  if (dueIn <= 0) return { days: dueIn, label: dueIn === 0 ? 'Today' : `${Math.abs(dueIn)}d overdue`, cls: 'due-overdue' };
  if (dueIn <= 2) return { days: dueIn, label: `${dueIn}d`, cls: 'due-soon' };
  return { days: dueIn, label: `${dueIn}d`, cls: 'due-ok' };
}

function getLastReviewMs(p) {
  const ud = userData[p.id];
  if (ud && ud.lastReviewed) {
    const t = new Date(ud.lastReviewed).getTime();
    if (!isNaN(t)) return t;
  }
  if (p.date) {
    const parts = p.date.split(' ');
    if (parts.length === 3) {
      const d = new Date(parts[1] + ' ' + parts[0] + ', ' + parts[2]);
      if (!isNaN(d)) return d.getTime();
    }
  }
  return null;
}

function computeXP() {
  const diffMult = { Easy: 1, Medium: 2, Hard: 3 };
  let baseXP = 0;
  let slain = 0;
  RAW_PROBLEMS.forEach(p => {
    const c = getConfForXP(p);
    if (c > 0) {
      slain++;
      baseXP += c * (diffMult[p.diff] || 1);
    }
  });
  return { totalXP: baseXP, slain };
}

function saveState() {
  try {
    localStorage.setItem('dsa_dojo_data', JSON.stringify(userData));
    scheduleSyncWrite();
  } catch(e) {
    console.warn('Failed to save state:', e);
    showToast('Storage full — export your progress!', 'error');
  }
}

function loadState() {
  try {
    const saved = localStorage.getItem('dsa_dojo_data');
    if (saved) userData = JSON.parse(saved);
    const plan = localStorage.getItem('dsa_dojo_plan');
    if (plan) todayPlan = JSON.parse(plan);
  } catch(e) {
    console.warn('Failed to load saved state:', e);
  }
}

function exportProgress() {
  const data = { userData, todayPlan, exportedAt: new Date().toISOString(), version: 1 };
  const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
  const a = document.createElement('a');
  a.href = URL.createObjectURL(blob);
  a.download = `dsa-dojo-progress-${new Date().toISOString().split('T')[0]}.json`;
  a.click();
  URL.revokeObjectURL(a.href);
  showToast('Progress exported!', 'success');
}

function importProgress(e) {
  const file = e.target.files[0];
  if (!file) return;
  const reader = new FileReader();
  reader.onload = function(ev) {
    try {
      const data = JSON.parse(ev.target.result);
      if (!data.userData) throw new Error('Invalid file');
      const count = Object.keys(data.userData).length;
      userData = data.userData;
      if (data.todayPlan) todayPlan = data.todayPlan;
      saveState();
      savePlan();
      scheduleSyncWrite();
      applyFilters();
      renderDashboard();
      renderToday();
      updateHeroStats();
      updateBadges();
      showToast(`Imported ${count} records!`, 'success');
    } catch (err) {
      showToast('Invalid file — could not import', 'error');
    }
  };
  reader.readAsText(file);
  e.target.value = '';
}

function openSyncDb() {
  return new Promise((resolve, reject) => {
    const req = indexedDB.open(SYNC_DB_NAME, 1);
    req.onupgradeneeded = () => {
      const db = req.result;
      if (!db.objectStoreNames.contains(SYNC_DB_STORE)) db.createObjectStore(SYNC_DB_STORE);
    };
    req.onsuccess = () => resolve(req.result);
    req.onerror = () => reject(req.error);
  });
}

async function setStoredSyncHandle(handle) {
  const db = await openSyncDb();
  await new Promise((resolve, reject) => {
    const tx = db.transaction(SYNC_DB_STORE, 'readwrite');
    tx.objectStore(SYNC_DB_STORE).put(handle, SYNC_HANDLE_KEY);
    tx.oncomplete = resolve;
    tx.onerror = () => reject(tx.error);
  });
  db.close();
}

async function getStoredSyncHandle() {
  const db = await openSyncDb();
  const handle = await new Promise((resolve, reject) => {
    const tx = db.transaction(SYNC_DB_STORE, 'readonly');
    const req = tx.objectStore(SYNC_DB_STORE).get(SYNC_HANDLE_KEY);
    req.onsuccess = () => resolve(req.result || null);
    req.onerror = () => reject(req.error);
  });
  db.close();
  return handle;
}

function setSyncStatus(text) {
  ['sync-status-desktop', 'sync-status-mobile'].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.textContent = text;
  });
}

function setSyncButtonLabel(text) {
  ['sync-btn-desktop', 'sync-btn-mobile'].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.innerHTML = text;
  });
}

function updateSyncUI() {
  if (!supportsProgressSync()) {
    setSyncStatus('Sync: Unsupported browser');
    setSyncButtonLabel('Sync NA');
    return;
  }
  if (!syncFileHandle) {
    setSyncStatus('Sync: Local only');
    setSyncButtonLabel('Connect Sync');
    return;
  }
  setSyncStatus('Sync: Connected');
  setSyncButtonLabel('Reconnect Sync');
}

function supportsProgressSync() {
  return typeof window !== 'undefined' &&
    'indexedDB' in window &&
    'showOpenFilePicker' in window &&
    'showSaveFilePicker' in window;
}

async function ensureSyncPermission(mode = 'readwrite') {
  if (!syncFileHandle) return false;
  try {
    const queried = await syncFileHandle.queryPermission({ mode });
    if (queried === 'granted') return true;
    const requested = await syncFileHandle.requestPermission({ mode });
    return requested === 'granted';
  } catch (e) {
    console.warn('Sync permission check failed:', e);
    return false;
  }
}

async function writeSyncSnapshot() {
  if (!syncFileHandle || syncWriteSuppressed) return;
  const permitted = await ensureSyncPermission('readwrite');
  if (!permitted) {
    setSyncStatus('Sync: Permission needed');
    return;
  }
  try {
    const data = { userData, todayPlan, exportedAt: new Date().toISOString(), version: 1 };
    const writable = await syncFileHandle.createWritable();
    await writable.write(JSON.stringify(data, null, 2));
    await writable.close();
    setSyncStatus('Sync: Connected');
  } catch (e) {
    console.warn('Sync write failed:', e);
    setSyncStatus('Sync: Write failed');
  }
}

function scheduleSyncWrite() {
  if (!syncFileHandle || syncWriteSuppressed) return;
  if (syncWriteTimer) clearTimeout(syncWriteTimer);
  syncWriteTimer = setTimeout(() => { writeSyncSnapshot(); }, 450);
}

async function loadFromSyncFile() {
  if (!syncFileHandle) return false;
  const permitted = await ensureSyncPermission('read');
  if (!permitted) {
    setSyncStatus('Sync: Permission needed');
    return false;
  }
  try {
    const file = await syncFileHandle.getFile();
    const text = await file.text();
    if (!text.trim()) return false;
    const data = JSON.parse(text);
    if (!data || !data.userData) return false;
    syncWriteSuppressed = true;
    userData = data.userData || {};
    todayPlan = data.todayPlan || [];
    localStorage.setItem('dsa_dojo_data', JSON.stringify(userData));
    localStorage.setItem('dsa_dojo_plan', JSON.stringify(todayPlan));
    syncWriteSuppressed = false;
    setSyncStatus('Sync: Loaded');
    return true;
  } catch (e) {
    syncWriteSuppressed = false;
    console.warn('Sync read failed:', e);
    setSyncStatus('Sync: Read failed');
    return false;
  }
}

async function connectProgressSync() {
  if (!supportsProgressSync()) {
    showToast('This browser does not support file sync mode', 'error');
    updateSyncUI();
    return;
  }
  try {
    let handle = null;
    try {
      const picked = await window.showOpenFilePicker({
        multiple: false,
        types: [{ description: 'JSON Progress File', accept: { 'application/json': ['.json'] } }]
      });
      handle = picked && picked[0];
    } catch (e) {
      handle = await window.showSaveFilePicker({
        suggestedName: 'dsa-dojo-progress-sync.json',
        types: [{ description: 'JSON Progress File', accept: { 'application/json': ['.json'] } }]
      });
    }
    if (!handle) return;
    syncFileHandle = handle;
    await setStoredSyncHandle(handle);
    updateSyncUI();
    const loaded = await loadFromSyncFile();
    if (loaded) {
      applyFilters();
      renderDashboard();
      renderToday();
      updateHeroStats();
      updateBadges();
      showToast('Sync connected and loaded', 'success');
    } else {
      await writeSyncSnapshot();
      showToast('Sync connected', 'success');
    }
  } catch (e) {
    if (e && e.name === 'AbortError') return;
    console.warn('Connect sync failed:', e);
    showToast('Could not connect sync file', 'error');
  }
}

async function initProgressSync() {
  updateSyncUI();
  if (!supportsProgressSync()) return;
  try {
    const handle = await getStoredSyncHandle();
    if (!handle) return;
    syncFileHandle = handle;
    updateSyncUI();
    const loaded = await loadFromSyncFile();
    if (!loaded) return;
    applyFilters();
    renderDashboard();
    renderToday();
    updateHeroStats();
    updateBadges();
  } catch (e) {
    console.warn('Init sync failed:', e);
    setSyncStatus('Sync: Reconnect needed');
  }
}

function generatePlan() {
  const n = Math.min(50, Math.max(1, parseInt(document.getElementById('rev-count').value)||10));
  const minReviewsRequested = Math.min(n, Math.max(0, parseInt(document.getElementById('rev-min-reviews')?.value)||0));
  const now = Date.now();
  const DAY = 86400000;
  const todayIso = new Date().toISOString().split('T')[0];

  const slainByDiff = { Easy: 0, Medium: 0, Hard: 0 };
  const slainByTopic = {};
  const totalByTopic = {};
  RAW_PROBLEMS.forEach(p => {
    const t = p.topic.split('/')[0].trim();
    totalByTopic[t] = (totalByTopic[t] || 0) + 1;
    if (getConf(p) > 0) {
      slainByDiff[p.diff] = (slainByDiff[p.diff] || 0) + 1;
      slainByTopic[t] = (slainByTopic[t] || 0) + 1;
    }
  });
  const totalSlain = slainByDiff.Easy + slainByDiff.Medium + slainByDiff.Hard;

  // Separate into two buckets: due reviews vs new/unseen
  const reviews = [];
  const unseen = [];

  RAW_PROBLEMS.forEach(p => {
    const ud = getUD(p.id);
    const c = getConf(p);
    const t = p.topic.split('/')[0].trim();
    const topicMastery = (slainByTopic[t] || 0) / (totalByTopic[t] || 1);
    const snoozeUntilMs = ud.snoozeUntil ? new Date(ud.snoozeUntil).getTime() : 0;
    const isSnoozed = snoozeUntilMs > now;
    const isPinned = !!ud.pinTomorrow;

    if (isSnoozed && !isPinned) return;

    if (c > 0) {
      let daysSince = 999;
      if (ud.lastReviewed) {
        daysSince = Math.floor((now - new Date(ud.lastReviewed).getTime()) / DAY);
      } else if (p.date) {
        const parts = p.date.split(' ');
        if (parts.length === 3) {
          const d = new Date(parts[1] + ' ' + parts[0] + ', ' + parts[2]);
          if (!isNaN(d)) daysSince = Math.floor((now - d.getTime()) / DAY);
        }
      }
      const interval = SR_INTERVALS[Math.min(c, 5)];
      const overdue = daysSince - interval;
      if (overdue >= 0) {
        const urgency = Math.min(overdue, 90) * 2;
        const weaknessBonus = (5 - c) * 10;
        const why = overdue > 0 ? `Overdue ${overdue}d` : (c <= 2 ? `Low confidence (${c}/5)` : 'Due review');
        reviews.push({ ...p, _score: urgency + weaknessBonus + Math.random() * 2, _conf: c, _type: 'review', _why: why });
      }
    } else {
      // Difficulty gating based on overall + per-topic progression
      let eligible = true;
      let priority = 0;
      const diffBase = { Easy: 100, Medium: 50, Hard: 10 };
      priority = diffBase[p.diff] || 50;

      if (p.diff === 'Hard') {
        if (totalSlain < 20) eligible = false;
        else if (slainByDiff.Easy < 15 || slainByDiff.Medium < 10) eligible = false;
        else if (topicMastery < 0.3) eligible = false;
        else priority += topicMastery * 30;
      } else if (p.diff === 'Medium') {
        if (totalSlain < 5) eligible = false;
        else if (slainByDiff.Easy < 5) eligible = false;
        else priority += topicMastery * 20;
      } else {
        priority += 50;
      }

      if (eligible) {
        unseen.push({ ...p, _score: priority + Math.random() * 5, _conf: 0, _type: 'new', _why: 'New unlock' });
      }
    }
  });

  reviews.sort((a, b) => b._score - a._score);
  unseen.sort((a, b) => b._score - a._score);

  // Allocation: reviews get priority, fill remainder with new problems.
  // Enforce user-selected minimum reviews when available.
  const targetReviewSlots = Math.max(Math.ceil(n * 0.7), minReviewsRequested);

  const picked = [];
  const topicCount = {};
  const maxPerTopic = Math.max(2, Math.ceil(n / 4));
  const pinnedPool = RAW_PROBLEMS
    .filter(p => getUD(p.id).pinTomorrow)
    .map(p => ({ ...p, _score: 9999, _conf: getConf(p), _type: 'pinned', _why: 'Pinned for tomorrow' }));

  function pickFrom(pool, limit) {
    let added = 0;
    for (const p of pool) {
      if (added >= limit) break;
      const t = p.topic.split('/')[0].trim();
      if ((topicCount[t] || 0) < maxPerTopic) {
        picked.push(p);
        topicCount[t] = (topicCount[t] || 0) + 1;
        added++;
      }
    }
    return added;
  }

  pickFrom(pinnedPool, n);
  const reviewCapacity = Math.max(0, n - picked.length);
  const reviewLimit = Math.min(reviews.length, targetReviewSlots, reviewCapacity);
  pickFrom(reviews, reviewLimit);
  const remainingSlots = Math.max(0, n - picked.length);
  pickFrom(unseen, remainingSlots);

  // If we didn't fill enough, relax topic limits
  if (picked.length < n) {
    const ids = new Set(picked.map(x => x.id));
    const remaining = [...reviews, ...unseen].filter(x => !ids.has(x.id));
    remaining.sort((a, b) => b._score - a._score);
    for (const p of remaining) {
      if (picked.length >= n) break;
      picked.push(p);
    }
  }

  // Sort: Easy -> Medium -> Hard for session flow
  const diffOrder = { Easy: 0, Medium: 1, Hard: 2 };
  picked.sort((a, b) => (diffOrder[a.diff] || 1) - (diffOrder[b.diff] || 1));

  todayPlan = picked.map(p => ({ id: p.id, done: false, why: p._why || '', questType: p._type || 'new' }));
  let updatedPins = false;
  picked.forEach(p => {
    const ud = userData[p.id];
    if (ud && ud.pinTomorrow) {
      ud.pinTomorrow = false;
      updatedPins = true;
    }
  });
  if (updatedPins) saveState();
  savePlan();
  renderToday();
  const rc = picked.filter(x => x._type === 'review').length;
  const nc = picked.filter(x => x._type === 'new').length;
  const pc = picked.filter(x => x._type === 'pinned').length;
  showToast(`Quest accepted: ${rc} review${rc!==1?'s':''}, ${nc} new encounter${nc!==1?'s':''}${pc ? `, ${pc} pinned` : ''}`, 'info');
  updateBadges();
}

let userData = {};

let todayPlan = [];

let activePage = "dashboard";

let activeModal = null;

let bestStreak = 0;

let syncFileHandle = null;

let syncWriteTimer = null;

let syncWriteSuppressed = false;

const SYNC_DB_NAME = "dojo-sync";

const SYNC_DB_STORE = "handles";

const SYNC_HANDLE_KEY = "progressFile";
